import{_ as e,o as r,c as t,ai as i}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"消息队列项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/message-queue.md","filePath":"open-source/message-queue.md"}'),l={name:"open-source/message-queue.md"};function h(o,a,n,s,b,u){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="消息队列项目" tabindex="-1">消息队列项目 <a class="header-anchor" href="#消息队列项目" aria-label="Permalink to “消息队列项目”">​</a></h1><p>本页面精选了消息队列相关的开源项目，包括MQ服务器、客户端、监控工具等。</p><h2 id="rabbitmq" tabindex="-1">RabbitMQ <a class="header-anchor" href="#rabbitmq" aria-label="Permalink to “RabbitMQ”">​</a></h2><h3 id="核心服务器" tabindex="-1">核心服务器 <a class="header-anchor" href="#核心服务器" aria-label="Permalink to “核心服务器”">​</a></h3><ul><li><strong>RabbitMQ</strong>：开源消息代理 <ul><li>GitHub: <a href="https://github.com/rabbitmq/rabbitmq-server" target="_blank" rel="noreferrer">https://github.com/rabbitmq/rabbitmq-server</a></li><li>特点: AMQP协议、集群支持、多种语言客户端</li></ul></li></ul><h3 id="管理工具" tabindex="-1">管理工具 <a class="header-anchor" href="#管理工具" aria-label="Permalink to “管理工具”">​</a></h3><ul><li><strong>RabbitMQ Management Plugin</strong>：Web管理界面 <ul><li>GitHub: <a href="https://github.com/rabbitmq/rabbitmq-management" target="_blank" rel="noreferrer">https://github.com/rabbitmq/rabbitmq-management</a></li><li>功能: 队列监控、连接管理、消息追踪</li></ul></li></ul><h3 id="客户端库" tabindex="-1">客户端库 <a class="header-anchor" href="#客户端库" aria-label="Permalink to “客户端库”">​</a></h3><ul><li><p><strong>RabbitMQ Java Client</strong>：Java客户端</p><ul><li>GitHub: <a href="https://github.com/rabbitmq/rabbitmq-java-client" target="_blank" rel="noreferrer">https://github.com/rabbitmq/rabbitmq-java-client</a></li><li>功能: AMQP协议实现</li></ul></li><li><p><strong>Pika</strong>：Python客户端</p><ul><li>GitHub: <a href="https://github.com/pika/pika" target="_blank" rel="noreferrer">https://github.com/pika/pika</a></li><li>特点: 异步支持、连接池</li></ul></li></ul><h2 id="apache-kafka" tabindex="-1">Apache Kafka <a class="header-anchor" href="#apache-kafka" aria-label="Permalink to “Apache Kafka”">​</a></h2><h3 id="核心服务器-1" tabindex="-1">核心服务器 <a class="header-anchor" href="#核心服务器-1" aria-label="Permalink to “核心服务器”">​</a></h3><ul><li><strong>Apache Kafka</strong>：分布式流处理平台 <ul><li>GitHub: <a href="https://github.com/apache/kafka" target="_blank" rel="noreferrer">https://github.com/apache/kafka</a></li><li>特点: 高吞吐量、持久化、水平扩展</li></ul></li></ul><h3 id="管理工具-1" tabindex="-1">管理工具 <a class="header-anchor" href="#管理工具-1" aria-label="Permalink to “管理工具”">​</a></h3><ul><li><p><strong>Kafka Manager</strong>：Kafka管理界面</p><ul><li>GitHub: <a href="https://github.com/yahoo/kafka-manager" target="_blank" rel="noreferrer">https://github.com/yahoo/kafka-manager</a></li><li>功能: 集群管理、主题监控</li></ul></li><li><p><strong>Kafka Tool</strong>：Kafka GUI工具</p><ul><li>GitHub: <a href="https://github.com/kafkatool/kafkatool" target="_blank" rel="noreferrer">https://github.com/kafkatool/kafkatool</a></li><li>功能: 消息浏览、生产消费</li></ul></li></ul><h3 id="客户端库-1" tabindex="-1">客户端库 <a class="header-anchor" href="#客户端库-1" aria-label="Permalink to “客户端库”">​</a></h3><ul><li><p><strong>Kafka Java Client</strong>：Java客户端</p><ul><li>GitHub: <a href="https://github.com/apache/kafka" target="_blank" rel="noreferrer">https://github.com/apache/kafka</a></li><li>功能: Producer、Consumer API</li></ul></li><li><p><strong>kafka-python</strong>：Python客户端</p><ul><li>GitHub: <a href="https://github.com/dpkp/kafka-python" target="_blank" rel="noreferrer">https://github.com/dpkp/kafka-python</a></li><li>特点: 纯Python实现</li></ul></li></ul><h2 id="apache-rocketmq" tabindex="-1">Apache RocketMQ <a class="header-anchor" href="#apache-rocketmq" aria-label="Permalink to “Apache RocketMQ”">​</a></h2><h3 id="核心服务器-2" tabindex="-1">核心服务器 <a class="header-anchor" href="#核心服务器-2" aria-label="Permalink to “核心服务器”">​</a></h3><ul><li><strong>Apache RocketMQ</strong>：分布式消息中间件 <ul><li>GitHub: <a href="https://github.com/apache/rocketmq" target="_blank" rel="noreferrer">https://github.com/apache/rocketmq</a></li><li>特点: 高可用、低延迟、万亿级消息容量</li></ul></li></ul><h3 id="管理工具-2" tabindex="-1">管理工具 <a class="header-anchor" href="#管理工具-2" aria-label="Permalink to “管理工具”">​</a></h3><ul><li><strong>RocketMQ Console</strong>：管理控制台 <ul><li>GitHub: <a href="https://github.com/apache/rocketmq-externals" target="_blank" rel="noreferrer">https://github.com/apache/rocketmq-externals</a></li><li>功能: 集群监控、消息查询</li></ul></li></ul><h3 id="客户端库-2" tabindex="-1">客户端库 <a class="header-anchor" href="#客户端库-2" aria-label="Permalink to “客户端库”">​</a></h3><ul><li><strong>RocketMQ Java Client</strong>：Java客户端 <ul><li>GitHub: <a href="https://github.com/apache/rocketmq-client-java" target="_blank" rel="noreferrer">https://github.com/apache/rocketmq-client-java</a></li><li>功能: 生产消费、事务消息</li></ul></li></ul><h2 id="apache-activemq" tabindex="-1">Apache ActiveMQ <a class="header-anchor" href="#apache-activemq" aria-label="Permalink to “Apache ActiveMQ”">​</a></h2><h3 id="核心服务器-3" tabindex="-1">核心服务器 <a class="header-anchor" href="#核心服务器-3" aria-label="Permalink to “核心服务器”">​</a></h3><ul><li><strong>Apache ActiveMQ</strong>：开源消息代理 <ul><li>GitHub: <a href="https://github.com/apache/activemq" target="_blank" rel="noreferrer">https://github.com/apache/activemq</a></li><li>特点: JMS支持、多种协议</li></ul></li></ul><h3 id="artemis-activemq-6" tabindex="-1">Artemis (ActiveMQ 6) <a class="header-anchor" href="#artemis-activemq-6" aria-label="Permalink to “Artemis (ActiveMQ 6)”">​</a></h3><ul><li><strong>Apache ActiveMQ Artemis</strong>：下一代ActiveMQ <ul><li>GitHub: <a href="https://github.com/apache/activemq-artemis" target="_blank" rel="noreferrer">https://github.com/apache/activemq-artemis</a></li><li>特点: 高性能、非阻塞架构</li></ul></li></ul><h2 id="redis-消息队列" tabindex="-1">Redis 消息队列 <a class="header-anchor" href="#redis-消息队列" aria-label="Permalink to “Redis 消息队列”">​</a></h2><h3 id="基于redis的mq" tabindex="-1">基于Redis的MQ <a class="header-anchor" href="#基于redis的mq" aria-label="Permalink to “基于Redis的MQ”">​</a></h3><ul><li><strong>Redis</strong>：内存数据结构存储 <ul><li>GitHub: <a href="https://github.com/redis/redis" target="_blank" rel="noreferrer">https://github.com/redis/redis</a></li><li>功能: 发布订阅、列表、流</li></ul></li></ul><h3 id="redis-mq库" tabindex="-1">Redis MQ库 <a class="header-anchor" href="#redis-mq库" aria-label="Permalink to “Redis MQ库”">​</a></h3><ul><li><p><strong>Bull</strong>：Node.js Redis队列</p><ul><li>GitHub: <a href="https://github.com/OptimalBits/bull" target="_blank" rel="noreferrer">https://github.com/OptimalBits/bull</a></li><li>功能: 作业队列、延迟任务</li></ul></li><li><p><strong>RQ (Redis Queue)</strong>：Python Redis队列</p><ul><li>GitHub: <a href="https://github.com/rq/rq" target="_blank" rel="noreferrer">https://github.com/rq/rq</a></li><li>功能: 任务队列、工作者进程</li></ul></li></ul><h2 id="其他消息队列" tabindex="-1">其他消息队列 <a class="header-anchor" href="#其他消息队列" aria-label="Permalink to “其他消息队列”">​</a></h2><h3 id="nats" tabindex="-1">NATS <a class="header-anchor" href="#nats" aria-label="Permalink to “NATS”">​</a></h3><ul><li><strong>NATS</strong>：云原生消息系统 <ul><li>GitHub: <a href="https://github.com/nats-io/nats-server" target="_blank" rel="noreferrer">https://github.com/nats-io/nats-server</a></li><li>特点: 高性能、简单易用</li></ul></li></ul><h3 id="nsq" tabindex="-1">NSQ <a class="header-anchor" href="#nsq" aria-label="Permalink to “NSQ”">​</a></h3><ul><li><strong>NSQ</strong>：实时分布式消息平台 <ul><li>GitHub: <a href="https://github.com/nsqio/nsq" target="_blank" rel="noreferrer">https://github.com/nsqio/nsq</a></li><li>特点: 分布式、无单点故障</li></ul></li></ul><h3 id="zeromq" tabindex="-1">ZeroMQ <a class="header-anchor" href="#zeromq" aria-label="Permalink to “ZeroMQ”">​</a></h3><ul><li><strong>ZeroMQ</strong>：高性能异步消息库 <ul><li>GitHub: <a href="https://github.com/zeromq/libzmq" target="_blank" rel="noreferrer">https://github.com/zeromq/libzmq</a></li><li>特点: 多种模式、跨语言支持</li></ul></li></ul><h2 id="消息队列监控" tabindex="-1">消息队列监控 <a class="header-anchor" href="#消息队列监控" aria-label="Permalink to “消息队列监控”">​</a></h2><h3 id="通用监控" tabindex="-1">通用监控 <a class="header-anchor" href="#通用监控" aria-label="Permalink to “通用监控”">​</a></h3><ul><li><p><strong>Kafka Monitor</strong>：Kafka监控工具</p><ul><li>GitHub: <a href="https://github.com/linkedin/kafka-monitor" target="_blank" rel="noreferrer">https://github.com/linkedin/kafka-monitor</a></li><li>功能: 端到端延迟监控</li></ul></li><li><p><strong>RabbitMQ Prometheus Plugin</strong>：RabbitMQ监控</p><ul><li>GitHub: <a href="https://github.com/rabbitmq/rabbitmq-prometheus" target="_blank" rel="noreferrer">https://github.com/rabbitmq/rabbitmq-prometheus</a></li><li>功能: Prometheus指标导出</li></ul></li></ul><h3 id="管理平台" tabindex="-1">管理平台 <a class="header-anchor" href="#管理平台" aria-label="Permalink to “管理平台”">​</a></h3><ul><li><strong>Kafdrop</strong>：Kafka Web UI <ul><li>GitHub: <a href="https://github.com/obsidiandynamics/kafdrop" target="_blank" rel="noreferrer">https://github.com/obsidiandynamics/kafdrop</a></li><li>功能: 主题浏览、消息查看</li></ul></li></ul><h2 id="消息队列客户端" tabindex="-1">消息队列客户端 <a class="header-anchor" href="#消息队列客户端" aria-label="Permalink to “消息队列客户端”">​</a></h2><h3 id="java" tabindex="-1">Java <a class="header-anchor" href="#java" aria-label="Permalink to “Java”">​</a></h3><ul><li><p><strong>Spring AMQP</strong>：Spring消息抽象</p><ul><li>GitHub: <a href="https://github.com/spring-projects/spring-amqp" target="_blank" rel="noreferrer">https://github.com/spring-projects/spring-amqp</a></li><li>功能: RabbitMQ集成</li></ul></li><li><p><strong>Spring Kafka</strong>：Spring Kafka集成</p><ul><li>GitHub: <a href="https://github.com/spring-projects/spring-kafka" target="_blank" rel="noreferrer">https://github.com/spring-projects/spring-kafka</a></li><li>功能: Kafka集成</li></ul></li></ul><h3 id="python" tabindex="-1">Python <a class="header-anchor" href="#python" aria-label="Permalink to “Python”">​</a></h3><ul><li><strong>Celery</strong>：分布式任务队列 <ul><li>GitHub: <a href="https://github.com/celery/celery" target="_blank" rel="noreferrer">https://github.com/celery/celery</a></li><li>支持: RabbitMQ、Redis等多种后端</li></ul></li></ul><h3 id="node-js" tabindex="-1">Node.js <a class="header-anchor" href="#node-js" aria-label="Permalink to “Node.js”">​</a></h3><ul><li><strong>Bull</strong>：Node.js队列库 <ul><li>GitHub: <a href="https://github.com/OptimalBits/bull" target="_blank" rel="noreferrer">https://github.com/OptimalBits/bull</a></li><li>功能: Redis队列、作业调度</li></ul></li></ul><h2 id="流处理框架" tabindex="-1">流处理框架 <a class="header-anchor" href="#流处理框架" aria-label="Permalink to “流处理框架”">​</a></h2><ul><li><p><strong>Apache Flink</strong>：流处理框架</p><ul><li>GitHub: <a href="https://github.com/apache/flink" target="_blank" rel="noreferrer">https://github.com/apache/flink</a></li><li>功能: 实时流处理、批处理</li></ul></li><li><p><strong>Apache Storm</strong>：分布式实时计算</p><ul><li>GitHub: <a href="https://github.com/apache/storm" target="_blank" rel="noreferrer">https://github.com/apache/storm</a></li><li>功能: 实时数据处理</li></ul></li><li><p><strong>Apache Spark Streaming</strong>：Spark流处理</p><ul><li>GitHub: <a href="https://github.com/apache/spark" target="_blank" rel="noreferrer">https://github.com/apache/spark</a></li><li>功能: 微批处理、实时分析</li></ul></li></ul>',54)])])}const m=e(l,[["render",h]]);export{p as __pageData,m as default};
